import requests
import uuid

BASE_URL = "http://localhost:3000/api"
TIMEOUT = 30

def test_update_non_existent_pack():
    non_existent_slug = "nonexistent-slug-123456"
    url = f"{BASE_URL}/packs/{non_existent_slug}"

    # Payload for update includes required fields 'name', 'slug', 'type', and 'creatorId'
    payload = {
        "name": "Non Existent Pack",
        "slug": non_existent_slug,
        "type": "adventure",
        "creatorId": str(uuid.uuid4())
    }

    headers = {
        "Content-Type": "application/json"
    }

    try:
        response = requests.put(url, json=payload, headers=headers, timeout=TIMEOUT)
    except requests.RequestException as e:
        raise AssertionError(f"Request to update non-existent pack failed: {e}")

    assert response.status_code == 404, f"Expected 404 Not Found, got {response.status_code}"
    try:
        resp_json = response.json()
        assert "error" in resp_json or "message" in resp_json, "Error response missing expected keys"
    except ValueError:
        pass

test_update_non_existent_pack()

import requests
import uuid

BASE_URL = "http://localhost:3000/api"
TIMEOUT = 30


def test_resolve_asset_with_valid_selections():
    # Step 1: Create a new pack as prerequisite
    pack_slug = None
    try:
        pack_payload = {
            "name": "Test Pack for Resolution",
            "slug": f"test-pack-resolution-{uuid.uuid4().hex[:8]}",
            "type": "homebrew",  # Corrected to allowed enum value
            "creatorId": str(uuid.uuid4())
        }
        res_pack = requests.post(
            f"{BASE_URL}/packs", json=pack_payload, timeout=TIMEOUT
        )
        assert res_pack.status_code == 201, f"Pack creation failed: {res_pack.text}"
        pack = res_pack.json()
        pack_slug = pack.get("slug")
        assert pack_slug == pack_payload["slug"]

        # Step 2: Create a new asset in the created pack
        asset_type = "class"  # Changed to allowed enum for asset type
        asset_index = "0"  # Changed index to string as required by API
        asset_payload = {
            "index": asset_index,
            "type": asset_type,
            "data": {
                "description": "Test character asset data",
                "attributes": {"strength": 10, "intelligence": 8}
            }
        }
        res_asset = requests.post(
            f"{BASE_URL}/packs/{pack_slug}/assets", json=asset_payload, timeout=TIMEOUT
        )
        assert res_asset.status_code == 201, f"Asset creation failed: {res_asset.text}"

        # Step 3: Prepare the selections payload referencing packSlug and selectors
        selections_payload = {
            "packSlug": pack_slug,
            "selectors": [
                {
                    "type": asset_type,
                    "index": asset_index
                }
            ]
        }

        # Step 4: Call rules resolution API
        res_resolve = requests.post(
            f"{BASE_URL}/rules/resolve",
            json=selections_payload,
            timeout=TIMEOUT
        )
        assert res_resolve.status_code == 200, f"Resolution failed: {res_resolve.text}"
        resolved_asset = res_resolve.json()

        # Step 5: Validate resolved asset payload has expected keys
        assert "type" in resolved_asset, "Missing 'type' in resolved asset"
        assert resolved_asset["type"] == asset_type
        assert "index" in resolved_asset, "Missing 'index' in resolved asset"
        assert resolved_asset["index"] == asset_index

    finally:
        # Cleanup: delete the asset and pack if created
        if pack_slug:
            try:
                requests.delete(
                    f"{BASE_URL}/packs/{pack_slug}", timeout=TIMEOUT
                )
            except Exception:
                pass


test_resolve_asset_with_valid_selections()
